        return new Response(JSON.stringify({error: e.message, source: 'exception'}), {status: 500, headers: {'Content-Type': 'application/json', 'Cache-Control': 'no-store', 'Access-Control-Allow-Origin': '*', 'X-Content-Type-Options': 'nosniff'}});
